compliant:
// Compliant: Logger named for enclosing type
class EnclosingType
{
    private readonly ILogger logger;

    public EnclosingType(ILoggerFactory loggerFactory)
    {
        logger = loggerFactory.CreateLogger<EnclosingType>(); // Compliant
    }
}

// Compliant: Using typeof for correct enclosing type
public class MyService
{
    private static readonly ILogger logger = LogManager.GetLogger(typeof(MyService)); // Compliant
}
